/**
 * Section EVENTS map for the `projects/motivation` UI (story 131 introduces it).
 *
 * Per design-log #134, every cross-component event in this section lives here with a namespaced
 * constant, a typed detail entry, a factory, a type alias, and an `HTMLElementEventMap`
 * augmentation. Currently only the speech-dictation events live here, but it scales as the
 * section grows.
 */

export const PROJECT_EVENTS = {
    DICTATION_START: 'projects:dictation-start',
    DICTATION_INTERIM: 'projects:dictation-interim',
    DICTATION_FINAL: 'projects:dictation-final',
    DICTATION_ERROR: 'projects:dictation-error',
} as const;

export interface ProjectEventMap {
    [PROJECT_EVENTS.DICTATION_START]: undefined;
    [PROJECT_EVENTS.DICTATION_INTERIM]: { text: string };
    [PROJECT_EVENTS.DICTATION_FINAL]: { text: string };
    [PROJECT_EVENTS.DICTATION_ERROR]: { code: string; message: string };
}

export type ProjectEvent<K extends keyof ProjectEventMap> = CustomEvent<ProjectEventMap[K]>;

export function createProjectEvent<K extends keyof ProjectEventMap>(
    type: K,
    detail: ProjectEventMap[K],
): ProjectEvent<K> {
    return new CustomEvent(type, { bubbles: true, composed: true, detail }) as ProjectEvent<K>;
}

export const createDictationStartEvent = () =>
    createProjectEvent(PROJECT_EVENTS.DICTATION_START, undefined);
export const createDictationInterimEvent = (detail: ProjectEventMap[typeof PROJECT_EVENTS.DICTATION_INTERIM]) =>
    createProjectEvent(PROJECT_EVENTS.DICTATION_INTERIM, detail);
export const createDictationFinalEvent = (detail: ProjectEventMap[typeof PROJECT_EVENTS.DICTATION_FINAL]) =>
    createProjectEvent(PROJECT_EVENTS.DICTATION_FINAL, detail);
export const createDictationErrorEvent = (detail: ProjectEventMap[typeof PROJECT_EVENTS.DICTATION_ERROR]) =>
    createProjectEvent(PROJECT_EVENTS.DICTATION_ERROR, detail);

export type DictationStartEvent = ProjectEvent<typeof PROJECT_EVENTS.DICTATION_START>;
export type DictationInterimEvent = ProjectEvent<typeof PROJECT_EVENTS.DICTATION_INTERIM>;
export type DictationFinalEvent = ProjectEvent<typeof PROJECT_EVENTS.DICTATION_FINAL>;
export type DictationErrorEvent = ProjectEvent<typeof PROJECT_EVENTS.DICTATION_ERROR>;

declare global {
    interface HTMLElementEventMap {
        [PROJECT_EVENTS.DICTATION_START]: DictationStartEvent;
        [PROJECT_EVENTS.DICTATION_INTERIM]: DictationInterimEvent;
        [PROJECT_EVENTS.DICTATION_FINAL]: DictationFinalEvent;
        [PROJECT_EVENTS.DICTATION_ERROR]: DictationErrorEvent;
    }
}
