import {
    SpeechDictation,
    isSpeechRecognitionSupported,
    getFriendlyErrorMessage,
} from '../../../utils/speech-dictation.js';
import {
    createDictationErrorEvent,
    createDictationFinalEvent,
    createDictationInterimEvent,
    createDictationStartEvent,
} from '../project-events.js';
import { cssStyleSheet } from '../../../utils/css.js';
import { createComponentLogger } from '../../../utils/component-logger.js';
import {
    createScreenStatusMixin,
    createScreenStatusNodes,
} from '../../_shared/screen-status.js';
import type { ScreenComponent } from '../../../types/screen-component.js';
import stylesText from './speech-dictation.css?inline';

const styles = cssStyleSheet(stylesText);

const template = document.createElement('template');
template.innerHTML = `
<button type="button" id="toggle" data-listening="false">
    <span class="icon" aria-hidden="true">🎤</span>
    <span class="label">Dictate</span>
</button>
<span class="unsupported" id="unsupported" hidden>Voice not supported in this browser.</span>
`;

/**
 * Mic-button widget. Wraps the Web Speech API through `SpeechDictation` and dispatches typed
 * `projects:dictation-*` events as text arrives. Audio streams to Chrome's recognizer (Google
 * servers — see the wrapper's notes); only the transcript is exposed to callers.
 *
 * Implements `ScreenComponent` (per development_principles.md) so callers can drive
 * `setLoading()` / `setError(err)` / `clearStatus()` and the standard `<pre class="screen-error">`
 * node renders the failure inline.
 */
export class SpeechDictationComponent extends HTMLElement implements ScreenComponent {
    private shadowRootRef: ShadowRoot;
    private toggleButton!: HTMLButtonElement;
    private unsupportedEl!: HTMLElement;
    private dictation: SpeechDictation | null = null;
    private readonly statusNodes = createScreenStatusNodes();
    private readonly statusMixin = createScreenStatusMixin(
        this.statusNodes.loadingNode,
        this.statusNodes.errorNode,
        this.statusNodes.retryNode,
    );
    private readonly log = createComponentLogger('speech-dictation-component');

    constructor() {
        super();
        this.shadowRootRef = this.attachShadow({ mode: 'open' });
        this.shadowRootRef.adoptedStyleSheets = [styles];
        this.shadowRootRef.appendChild(template.content.cloneNode(true));
        this.shadowRootRef.appendChild(this.statusNodes.loadingNode);
        this.shadowRootRef.appendChild(this.statusNodes.errorNode);
        this.shadowRootRef.appendChild(this.statusNodes.retryNode);
        this.statusNodes.retryNode.textContent = 'Try again';
        this.statusNodes.retryNode.addEventListener('click', () => {
            this.clearStatus();
            this.toggle();
        });
    }

    connectedCallback(): void {
        this.toggleButton = this.shadowRootRef.getElementById('toggle') as HTMLButtonElement;
        this.unsupportedEl = this.shadowRootRef.getElementById('unsupported') as HTMLElement;

        const supported = isSpeechRecognitionSupported();
        this.log.debug('connected', { supported, secureContext: window.isSecureContext, lang: document.documentElement.lang });
        if (!supported) {
            this.toggleButton.hidden = true;
            this.unsupportedEl.hidden = false;
            return;
        }

        this.toggleButton.addEventListener('click', () => this.toggle());
    }

    disconnectedCallback(): void {
        this.log.debug('disconnected — aborting any active dictation');
        this.dictation?.abort();
        this.dictation = null;
    }

    setLoading(): void { this.statusMixin.setLoading(); }
    setError(err: unknown): void { this.statusMixin.setError(err); }
    clearStatus(): void { this.statusMixin.clearStatus(); }

    private toggle(): void {
        if (!this.dictation) {
            this.log.debug('lazily creating SpeechDictation wrapper');
            this.dictation = new SpeechDictation({
                oninterim: (text) => {
                    this.log.debug('interim transcript chunk', { length: text.length });
                    this.clearStatus();
                    this.dispatchEvent(createDictationInterimEvent({ text }));
                },
                onfinal: (text) => {
                    this.log.debug('final transcript chunk', { length: text.length });
                    this.clearStatus();
                    this.dispatchEvent(createDictationFinalEvent({ text }));
                },
                onerror: ({ code, message }) => {
                    this.log.warn('dictation error → surfacing via setError', { code, message });
                    this.setError(new Error(getFriendlyErrorMessage(code, message)));
                    this.setListening(false);
                    this.dispatchEvent(createDictationErrorEvent({ code, message }));
                },
                onend: () => {
                    this.log.debug('dictation session ended (browser-driven) — syncing button state');
                    this.setListening(false);
                },
            });
        }
        if (this.dictation.isListening) {
            this.log.info('toggle → stop');
            this.dictation.stop();
            this.setListening(false);
        } else {
            this.log.info('toggle → start');
            this.clearStatus();
            this.dictation.start();
            this.setListening(true);
            this.dispatchEvent(createDictationStartEvent());
        }
    }

    private setListening(listening: boolean): void {
        this.log.debug('setListening', { listening });
        this.toggleButton.dataset.listening = String(listening);
        const label = this.toggleButton.querySelector('.label') as HTMLElement;
        label.textContent = listening ? 'Stop' : 'Dictate';
    }
}

if (!customElements.get('speech-dictation')) {
    customElements.define('speech-dictation', SpeechDictationComponent);
}
